sp_widget.css:
.gbd-ombudsman-and-protocol {
  padding-bottom: 5.6rem;
}

.gbd-ombudsman-and-protocol-title {
  color: #0c326f;
  font-weight: 600;
  font-size: 3.6rem;
  margin-top: 4rem;
  margin-bottom: 2.8rem;
  line-height: 1.5;
}

.gbd-ombudsman-and-protocol-subtitle {
  font-weight: 600;
  font-size: 2.2rem;
  color: #555;
  line-height: 3.2rem;
  margin-bottom: 2.4rem;
}

.card-ombudsman {
  box-sizing: border-box;
  min-height: 23rem;
  box-shadow: 0 3px 6px 0 rgba(0, 0, 0, 0.16);
  text-align: center;
  background-color: #ededed;
  margin-bottom: 3.6rem;
}

.card-ombudsman:hover {
  text-decoration: none;
  background-color: #dbe8fb;
}

.custon-fa { 
  font-size: 5rem;
  color: #0c326f;
}

.my-panel-body {
	padding: 5.5rem;
}

@media (max-width: 768px) {
  .card-ouvidoria { 
    margin-bottom: 15px; 
  }
}

sp_widget.script:
(function() {
	/* populate the 'data' object */
	/* e.g., data.table = $sp.getValue('incident'); */
	var cardsString = gs.getProperty('x_821667_my_widget.gbd.ombudsman.and.protocol') || '[]';
	var cardsJSON = JSON.parse(cardsString);
	var cards = [];

	cardsJSON.forEach(function(card) {
		cards.push({
			icon: card.icon,
			title: gs.getMessage(card.title),
			link: card.link
		});
	});

	data.cards = cards;
})();
